import{_ as e}from"./chunks/Gemini_Generated_Image_fug6l2fug6l2fug6.wlNFePn-.js";import{_ as r,o as d,c as t,ag as o}from"./chunks/framework.BZohXCq9.js";const b=JSON.parse('{"title":"什么是 Bamdra","description":"了解 Bamdra 的品牌定位、竹蜻蜓的含义，以及我们为什么专注于面向场景化 AI 应用的产品化建设。","frontmatter":{"title":"什么是 Bamdra","description":"了解 Bamdra 的品牌定位、竹蜻蜓的含义，以及我们为什么专注于面向场景化 AI 应用的产品化建设。"},"headers":[],"relativePath":"zh/guide/what-is-bamdra.md","filePath":"zh/guide/what-is-bamdra.md","lastUpdated":null}'),i={name:"zh/guide/what-is-bamdra.md"};function l(m,a,h,n,c,s){return d(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="什么是-bamdra" tabindex="-1">什么是 Bamdra <a class="header-anchor" href="#什么是-bamdra" aria-label="Permalink to &quot;什么是 Bamdra&quot;">​</a></h1><figure class="doc-figure doc-parallax"><img src="'+e+'" alt="Bamdra 品牌封面"><figcaption>Bamdra 代表一种对 AI 的理解: 由人类赋予目标，借由智能拓展边界，最终服务于人类判断。</figcaption></figure><h2 id="关于我们真正想做的事" tabindex="-1">关于我们真正想做的事 <a class="header-anchor" href="#关于我们真正想做的事" aria-label="Permalink to &quot;关于我们真正想做的事&quot;">​</a></h2><p>Bamdra 想做的，是让 AI 不再停留在工作的边缘，而是真正进入人们每天反复面对的复杂任务之中。它应该能够跨越中断、承接上下文、减少重复，并逐渐改变人与信息、人与流程、人与协作之间的组织方式。</p><h2 id="竹蜻蜓的含义" tabindex="-1">竹蜻蜓的含义 <a class="header-anchor" href="#竹蜻蜓的含义" aria-label="Permalink to &quot;竹蜻蜓的含义&quot;">​</a></h2><p>Bamdra 是竹蜻蜓的英文 <code>bamboo dragonfly</code> 演变而来的名字。竹蜻蜓之所以能起飞，是因为人赋予了它动力；而当它飞起来之后，它又能够看到更广阔的世界，抵达更高的视角。但它最终还是会回到人的手中，回到人的目标、判断和责任当中。</p><p>这正是我们对智能体的理解：</p><ul><li>人类赋予 AI 初始目标与方向</li><li>AI 帮助人类拓展能力与视野</li><li>最终的控制权、决策权与责任仍然属于人类</li></ul><h2 id="bamdra-的产品观" tabindex="-1">Bamdra 的产品观 <a class="header-anchor" href="#bamdra-的产品观" aria-label="Permalink to &quot;Bamdra 的产品观&quot;">​</a></h2><h3 id="为真实工作流而设计" tabindex="-1">为真实工作流而设计 <a class="header-anchor" href="#为真实工作流而设计" aria-label="Permalink to &quot;为真实工作流而设计&quot;">​</a></h3><p>我们服务的是运营、产品、研发、知识工作等真实协作流程，而不是只为概念展示打造功能。</p><h3 id="让智能更可控" tabindex="-1">让智能更可控 <a class="header-anchor" href="#让智能更可控" aria-label="Permalink to &quot;让智能更可控&quot;">​</a></h3><p>AI 可以帮助人抵达更远的地方，但必须保持可观察、可管理、可约束。</p><h3 id="重塑工作流-而不只是展示能力" tabindex="-1">重塑工作流，而不只是展示能力 <a class="header-anchor" href="#重塑工作流-而不只是展示能力" aria-label="Permalink to &quot;重塑工作流，而不只是展示能力&quot;">​</a></h3><p>真正重要的，不是 AI 证明自己“可以做到”，而是它是否真的让工作方式发生变化，让协作更加连续，让决策更少被遗忘，让复杂任务更容易推进。</p><h2 id="当前公开产品" tabindex="-1">当前公开产品 <a class="header-anchor" href="#当前公开产品" aria-label="Permalink to &quot;当前公开产品&quot;">​</a></h2><p>当前 Bamdra 对外公开的首个产品线是 Bamdra OpenClaw 记忆套件。它以 <code>bamdra-openclaw-memory</code> 为主仓库，并配套 <code>bamdra-user-bind</code> 与 <code>bamdra-memory-vector</code> 两个插件仓库，一起让 OpenClaw 会话拥有更强的连续性、记忆能力与上下文恢复能力。</p>',17)])])}const _=r(i,[["render",l]]);export{b as __pageData,_ as default};
